// @filename: utils.ts
// @noErrors
import { 
  Address,
  erc20Abi, 
  maxUint256, 
  getContract, 
  parseErc6492Signature, 
} from 'viem'
import { account, client } from './config'

const eip2612Abi = [
  ...erc20Abi,
  {
    inputs: [
      {
        internalType: 'address',
        name: 'owner',
        type: 'address',
      },
    ],
    stateMutability: 'view',
    type: 'function',
    name: 'nonces',
    outputs: [
      {
        internalType: 'uint256',
        name: '',
        type: 'uint256',
      },
    ],
  },
  {
    inputs: [],
    name: 'version',
    outputs: [{ internalType: 'string', name: '', type: 'string' }],
    stateMutability: 'view',
    type: 'function',
  },
] as const

export async function signPermit({
  permitAmount,
  spenderAddress,
  tokenAddress,
}: {
  permitAmount: bigint,
  spenderAddress: Address,
  tokenAddress: Address,
}) {
  const token = getContract({
    client,
    address: tokenAddress,
    abi: eip2612Abi,
  })

  const signature = await account.signTypedData(permitData)

  const [name, version, nonce] = await Promise.all([
    token.read.name(),
    token.read.version(),
    token.read.nonces([ownerAddress])
  ])

  const isValid = await client.verifyTypedData({
    address: account.address,
    types: {
      Permit: [
        { name: 'owner', type: 'address' },
        { name: 'spender', type: 'address' },
        { name: 'value', type: 'uint256' },
        { name: 'nonce', type: 'uint256' },
        { name: 'deadline', type: 'uint256' },
      ],
    },
    primaryType: 'Permit',
    domain: {
      chainId: chain.id,
      name,
      verifyingContract: token.address,
      version,
    },
    message: {
      owner: ownerAddress,
      spender: spenderAddress,
      value,
      nonce,
      deadline: maxUint256,
    },
    signature,
  })

  if (!isValid) 
    throw new Error(
      `Invalid permit signature for ${account.address}: ${wrappedPermitSignature}`,
    )


  const { signature: unwrappedSignature } = parseErc6492Signature(wrappedPermitSignature)
  return unwrappedSignature
}

